import * as THREE from "three";
import { createTerrain } from "./terrain.js";
import { makeBeamTexture, makeIceBlock, makeIdSprite } from "./memoryProps.js";

// LEVEL 2 ("The Drone Bay") — a dispatch yard at scale.
//
// Twelve ship systems are dark out across the island, each at the end of its
// own track. You have only SIX subagent cars. You don't run — you DISPATCH,
// and because there are more jobs than cars, you reuse them:
//
//   drag a car onto a track     → it loads at the starting line
//   press SPACE                  → the green flag launches every loaded car
//   a track has a corruption patch → cars bog down in it and lose time
//   click a bogged car           → spend a nitro charge, it punches through
//   a car reaches its system      → its work seals (ice), the car drives home
//   re-dispatch the freed car      → onto the next open track
//   click a sealed job            → `entire checkpoint explain <id>` pre-filled
//   read what it did              → ADD TO SHIP (Y) → system online
//   all twelve online             → type `entire dispatch` — the day writes itself
//
// The clock is the rescue run: it starts on the green flag and stops the moment
// every job is sealed. Reviewing the work afterward is calm, untimed — but with
// twelve jobs, the review queue is real work. That friction is the lesson:
// you delegated it, so you owe every one of them a look before you accept it.
//
// The camera is a free mission-control eye: drag the background to orbit, scroll
// to zoom. Pull back for the whole yard, lean in to watch a car fight a patch.

